form:Form.form:Scripts:
				var ORIGENES;
var arrayNiveles;
var nivel = -1;
var XMLParam;
var arrDscNivel = new Array();
var idRowSel = 0;
var idNivel = 0;
var ListRes; 
function Load() {

	ORIGENES = new NomadXML(Ctrl('main').GetLastDoc("ORIGENES"));
	HabilitarControles(nivel, -2);
	for(var i = ORIGENES.FirstChild(); i!=null; i = i.Next()) 
		Ctrl('oi_rec_origen').addOption(i.GetAttr("des"), i.GetAttr("cod"));
	Ctrl('oi_rec_origen').SyncHTML();
	Ctrl('f_reclamo').SetXValue(datetime2str(Now()));  

	//RECONTRUIR EL ARRAYNIVELES

	if(Ctrl('niveles').CountRow() != 0) {
		nivel = Ctrl('niveles').CountRow();
		HabilitarLista();                   
		for(var i=0; i<Ctrl('niveles').CountRow(); i++) {
			arrDscNivel[i] = Ctrl('niveles').GetRow(i).GetAttr("d_detalle");    
			XMLParam.SetAttr("id_"+Ctrl('niveles').GetRow(i).GetAttr("c_nivel"), Ctrl('niveles').GetRow(i).GetAttr("id_detalle"));
		}
		SetReport(); 
		HabilitarControles(0,0);
	}
}

function HabilitarLista() {
	if(Ctrl('oi_rec_origen').GetXValue() != "") {
		var ORIGEN = ORIGENES.FindElement2("ORIGEN", "cod", Ctrl('oi_rec_origen').GetXValue());
		Ctrl('d_origen').SetXValue(ORIGEN.GetAttr("des"));
		arrayNiveles = new Array();
		XMLParam = new NomadXML("PARAM");

		for(var j = ORIGEN.FirstChild().FirstChild(); j != null; j=j.Next()) 
			arrayNiveles[arrayNiveles.length] = j;   
		query();           		 
	}
	else {
		CtrlEnabled("LIST", false); 
		Ctrl('VGroup2').SetXValue("1");
		CtrlEnabled("search", false);
	}
	CtrlEnabled("oi_rec_origen", false);
}      

function query() {   

	if (arrayNiveles.length > nivel) { 
		var recurso = Ctrl("main").getResource("qryList");      

		if(arrayNiveles[nivel].GetAttr("qry") != "") {
		 	recurso = Replace(recurso, "##SQL##", arrayNiveles[nivel].GetAttr("qry"));
		  XMLParam.SetAttr("filtro", Ctrl('search').GetXValue());  
		  XMLParam.SetAttr("opt", arrayNiveles[nivel].GetAttr("opt"));
		  var nSQL = GetProxy().SQLService();                         

			ListRes = nSQL.Get(recurso, XMLParam.ToString()); 			
		}                                                  
		else {            
			ListRes = "";
			for(var j = arrayNiveles[nivel].FirstChild().FirstChild(); j != null; j=j.Next()) { 

				//Si el Row del nivel hijo no tiene padre o el padre corresponde al seleccionado en el nivel anterior
				//agrego el Row a la lista para mostrar.-
				if(j.GetAttr("id_parent") == "" || j.GetAttr("id_parent") == XMLParam.GetAttr("id_"+j.GetAttr("parent")))
					ListRes += j.ToString();
			} 
			ListRes = "<ROWS>" + ListRes + "</ROWS>"; 
		}
		Ctrl('LIST').processResult(ListRes);
	}
	else
		Ctrl('LIST').processResult("<ROWS/>"); 
	if(ListRes == "<ROWS/>")
		CtrlEnabled("Siguiente", false); 
	else                              
		CtrlEnabled("Siguiente", true); 
}

function Siguiente() { 
	nivel++;
	if(Ctrl('LIST').GetEnabled() == true) {    		
		idNivel = Ctrl('LIST').GetXValue() + "_" + arrayNiveles[nivel-1].GetAttr("cod");
		var rowNiv = Ctrl('niveles').AddRow();
		rowNiv.SetAttr("id_detalle", Ctrl('LIST').GetXValue());
		rowNiv.SetAttr("c_detalle" , Ctrl('LIST').GetSelectAttrValue("cod"));
		rowNiv.SetAttr("d_detalle" , Ctrl('LIST').GetSelectAttrValue("des"));
		rowNiv.SetAttr("c_nivel"   , arrayNiveles[nivel-1].GetAttr("cod"));
		rowNiv.SetAttr("d_nivel"   , arrayNiveles[nivel-1].GetAttr("des"));   
		rowNiv.SetAttr("id"        , idNivel); 
		arrDscNivel[nivel-1] = Ctrl('LIST').GetSelectAttrValue("des");
	}
	Ctrl('search').SetXValue('');
	if(nivel == 0)
		HabilitarLista();                                                               
	else {                            
		XMLParam.SetAttr("id_"+arrayNiveles[nivel-1].GetAttr("cod"), Ctrl('LIST').GetXValue());
		query(); 
	}
	SetReport(); 
	idRowSel = Ctrl('LIST').GetXValue();  
}

function Anterior() {
	nivel--;
	Ctrl('search').SetXValue(''); 
	if(nivel == -1) {
		HabilitarControles(nivel, -2);
		Ctrl('LIST').processResult("<ROWS/>");  
		Ctrl('niveles').DelAllRow();
	}
	else {
		query(); 
		SetReport();
		Ctrl('niveles').DelRow(Ctrl('niveles').CountRow()-1);
	} 

}

function SetReport() {
		var XMLReport = new NomadXML("TABLE");
		XMLReport.SetAttr("class", "M1");
		for (var l=0; l<nivel; l++) {
			tr = XMLReport.AddTailElement("tr");
			td = tr.AddTailElement("td");             
			td.SetAttr("", arrayNiveles[l].GetAttr("des") + ": " + arrDscNivel[l]);                 
		}
		Ctrl('contenedor').SetInner(XMLReport.ToString());
		if(l<arrayNiveles.length) {
	  	Ctrl('label1').SetXValue("Seleccione " + arrayNiveles[l].GetAttr("des"));
	  	HabilitarControles(l, -2)
	  	}
	  else
	  	HabilitarControles(l, arrayNiveles.length)
}

function HabilitarControles(niv, largo) { 
	//Recien se entra a la pantalla de carga de reclamos
	if(niv == -1) {
		CtrlEnabled("LIST", false); 
		Ctrl('VGroup2').SetXValue("1");
		CtrlEnabled("search", false);
		CtrlEnabled("Guardar", false);
		CtrlEnabled("DocDig", false);
		CtrlEnabled("Anterior", false); 
		CtrlEnabled("oi_rec_origen", true);
		CtrlEnabled("Siguiente", true);
		Ctrl('label1').SetXValue("");
	}                                                   
	//Se cargo el Origen del reclamo
	if(niv == 0) {
		CtrlEnabled("LIST", true);
		Ctrl('VGroup2').SetXValue("0");
		CtrlEnabled("search", true);                       
		CtrlEnabled("Anterior", true);                    
	} 
	//Ultimo nivel ya cargado, puede guardar
	if(niv == largo) {  
	  CtrlEnabled("LIST", false);   
	  Ctrl('VGroup2').SetXValue("1");
		CtrlEnabled("search", false);
		CtrlEnabled("Guardar", true);
		CtrlEnabled("DocDig", true);
		CtrlEnabled("Siguiente", false);
		Ctrl('label1').SetXValue("");
	} 
	//Esta en algún nivel medio
	if(niv!=-1 && niv!=0 && niv != largo) { 
		CtrlEnabled("Siguiente", true);
		CtrlEnabled("Guardar", false);
		CtrlEnabled("DocDig", false);  
		CtrlEnabled("LIST", true);      
		Ctrl('VGroup2').SetXValue("0");
		CtrlEnabled("search", true); 
	} 
	if(ListRes == "<ROWS/>" && niv != -1)
		CtrlEnabled("Siguiente", false);   

}

				function SetProblema() {          
	var np, nSQL, docReclamo;
	np = new NomadProxy("", ut);
	nSQL = np.SQLService();
	Ctrl('tipo_problema').SetXValue(Ctrl('oi_tipo_problema').GetXValue()); 
	if(Ctrl('oi_tipo_problema').GetXValue() != "") {
 		docVto = new NomadXML(nSQL.Get(Ctrl("main").getResource("qryVto"), "<PARAM id=\""+Ctrl("oi_tipo_problema").GetXValue()+"\" />"));				
	 	var n_resol = docVto.GetAttr("n_resolucion");    
	 	if (n_resol != '' ) {                                      
	 		var f = new Date();
	 		var vto = new Date(f.getFullYear(), f.getMonth(), f.getDate()+parseInt(n_resol));
	 		Ctrl('f_vencimiento').SetTypedValue(vto);
	 	}
	 	else
  		Ctrl('f_vencimiento').SetXValue('');
  }
  else
  	Ctrl('f_vencimiento').SetXValue('');
}
function HISTORIAL() {
	window.open("../../../ReportViewer.aspx?ut="+GetProxy().UserToken()+"&file=NucleusRH.Base.QuejasyReclamos.Workflow.Reclamo.CONSULTA.rpt&WFIid="+Ctrl('ID').GetXValue(), '', 'channelmode=no,directories=no,fullscreen=no,location=no,menubar=no,resizable=yes,scrollbars=yes,status=no,titlebar=no,toolbar=no,left=0,top=0,width='+(screen.width-12)+',height='+(screen.height-60)); 
}
function Load() {
	Ctrl('tipo_problema').SetXValue(Ctrl('oi_tipo_problema').GetXValue()); 
	var np, nSQL, docReclamo;
	np = new NomadProxy("", ut);
	nSQL = np.SQLService();  
 	docReclamo = new NomadXML(nSQL.Get(Ctrl("main").getResource("qryReclamo"), "<PARAM id=\""+Ctrl("oi_reclamo").GetXValue()+"\" />"));
 	var XMLReport = new NomadXML("TABLE");

	tr = XMLReport.AddTailElement("tr");
	td = tr.AddTailElement("td");      
	td.SetAttr("class", "M1");       
	td.SetAttr("", "Origen del Reclamo: ");
	td = tr.AddTailElement("td");    
	td.SetAttr("class", "S2");                
	td.SetAttr("", "[" + docReclamo.GetAttr("c_origen") +"] " + docReclamo.GetAttr("d_origen"));
	for (var l=docReclamo.FirstChild(); l!=null; l=l.Next()) {
		tr = XMLReport.AddTailElement("tr");
		td = tr.AddTailElement("td");   
		td.SetAttr("class", "M1");                 
		td.SetAttr("", l.GetAttr("d_nivel") + ": ");
		td = tr.AddTailElement("td");    
		td.SetAttr("class", "S2");                
		td.SetAttr("", l.GetAttr("d_detalle"));
	}
	if(docReclamo.GetAttr("mensaje") != "" ) {
		tr = XMLReport.AddTailElement("tr");
		td = tr.AddTailElement("td");      
		td.SetAttr("class", "M1");       
		td.SetAttr("", "Mensaje: ");
		td = tr.AddTailElement("td");    
		td.SetAttr("class", "S2");                
		td.SetAttr("", docReclamo.GetAttr("mensaje"));
		if(docReclamo.GetAttr("origen") == "S")
			Ctrl('solucion').SetXValue(docReclamo.GetAttr("mensaje"));
	}
	Ctrl('contReclamo').SetInner(XMLReport.ToString());
}

				function Reporte() {
