	td.SetAttr("class", "M1");       
	td.SetAttr("", "Origen del Reclamo: ");
	td = tr.AddTailElement("td");    
	td.SetAttr("class", "S2");                
	td.SetAttr("", "[" + docReclamo.GetAttr("c_origen") +"] " + docReclamo.GetAttr("d_origen"));

	c_detalle = "";
	d_detalle = "";
	for (var l=docReclamo.FirstChild(); l!=null; l=l.Next()) { 
	  if(d_detalle != l.GetAttr("d_detalle") && c_detalle != l.GetAttr("c_detalle")) {
			tr = XMLReport.AddTailElement("tr");
			td = tr.AddTailElement("td");   
			td.SetAttr("class", "M1");                 
			td.SetAttr("", l.GetAttr("d_nivel") + ": ");
			td = tr.AddTailElement("td");    
			td.SetAttr("class", "S2");                
			td.SetAttr("", l.GetAttr("d_detalle")); 
			d_detalle = l.GetAttr("d_detalle"); 
			c_detalle = l.GetAttr("c_detalle");
		}
	}

	tr = XMLReport.AddTailElement("tr"); 
	td = tr.AddTailElement("td");      
	td.SetAttr("class", "M1");
	td.SetAttr("valign", "top");              
	td.SetAttr("", "Solución: ");
	td = tr.AddTailElement("td");    
	td.SetAttr("class", "S2");                
	td.SetAttr("", docReclamo.GetAttr("t_solucion"));
	Ctrl('contReclamo').SetInner(Replace(XMLReport.ToString(), "{br}", "<br>"));       	
}

xsl:template.script:
			function downloadDoc(oi_doc_digital, o_doc_digital, ut) {
	var objIfrHidden = document.getElementById("ifrHidden");
	objIfrHidden.src = "./NomadFile.aspx?ut="+ut+String.fromCharCode(38)+"mode=DB"+String.fromCharCode(38)+"class=NucleusRH.Base.QuejasyReclamos.DocumentosDigitales.HEAD"+String.fromCharCode(38)+"id=" + oi_doc_digital +String.fromCharCode(38)+ "filename=" + o_doc_digital;
}
